CREATE SCHEMA IF NOT EXISTS staging;

CREATE TABLE IF NOT EXISTS staging.sp_incremental_sync_cursor (
    sync_key TEXT PRIMARY KEY,
    list_name TEXT NOT NULL,
    table_name TEXT NOT NULL,
    last_success_modified_at TIMESTAMPTZ NOT NULL DEFAULT '2000-01-01 00:00:00+00',
    last_success_at TIMESTAMPTZ,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS staging.sp_clientes_contai_raw (
    sp_id INTEGER PRIMARY KEY,
    payload JSONB NOT NULL,
    extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS staging.sp_recibe_helpdesk_raw (
    sp_id INTEGER PRIMARY KEY,
    payload JSONB NOT NULL,
    extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS staging.sp_personal_gct_raw (
    sp_id INTEGER PRIMARY KEY,
    payload JSONB NOT NULL,
    extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS staging.sp_tipo_req_hd_raw (
    sp_id INTEGER PRIMARY KEY,
    payload JSONB NOT NULL,
    extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS staging.sp_helpdesk_raw (
    sp_id INTEGER PRIMARY KEY,
    payload JSONB NOT NULL,
    extracted_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

SELECT NOW() AS infrastructure_checked_at;

