/**
 * Configuración declarativa de listas SharePoint legacy hacia tablas RAW.
 *
 * Notas:
 * - `initialSinceIso` permite una carga inicial desde histórico.
 * - El cursor real queda en staging.sp_incremental_sync_cursor.
 * - La capa RAW no decide qué es válido; la validación ocurre en los SQL de transformación.
 */
const lists = [
  {
    syncKey: "clientes_contai",
    listName: "Clientes Contai",
    tableName: "staging.sp_clientes_contai_raw",
    initialSinceIso: "2000-01-01T00:00:00Z",
  },
  {
    syncKey: "recibe_helpdesk",
    listName: "RecibeHelpdesk",
    tableName: "staging.sp_recibe_helpdesk_raw",
    initialSinceIso: "2000-01-01T00:00:00Z",
  },
  {
    syncKey: "personal_gct",
    listName: "Personal GCT",
    tableName: "staging.sp_personal_gct_raw",
    initialSinceIso: "2000-01-01T00:00:00Z",
  },
  {
    syncKey: "tipo_req_hd",
    listName: "TipoReqHD",
    tableName: "staging.sp_tipo_req_hd_raw",
    initialSinceIso: "2000-01-01T00:00:00Z",
  },
  {
    syncKey: "helpdesk_bd",
    listName: "HelpDeskBd",
    tableName: "staging.sp_helpdesk_raw",
    initialSinceIso: "2000-01-01T00:00:00Z",
  },
];

return lists.map((list) => ({ json: list }));

const response = $input.first()?.json ?? {};
const cursor = $("PG - Get List Cursor").first().json;
const values = Array.isArray(response.value) ? response.value : [];

const allowedTables = new Set([
  "staging.sp_clientes_contai_raw",
  "staging.sp_recibe_helpdesk_raw",
  "staging.sp_personal_gct_raw",
  "staging.sp_tipo_req_hd_raw",
  "staging.sp_helpdesk_raw",
]);

const tableName = cursor.table_name;

if (!allowedTables.has(tableName)) {
  throw new Error(`Tabla RAW no permitida para upsert dinámico: ${tableName}`);
}

function sqlString(value) {
  if (value === null || value === undefined) return "NULL";
  return `'${String(value).replace(/'/g, "''")}'`;
}

function jsonSql(value) {
  return `${sqlString(JSON.stringify(value))}::jsonb`;
}

if (values.length === 0) {
  return [
    {
      json: {
        has_items: false,
        sync_key: cursor.sync_key,
        list_name: cursor.list_name,
        table_name: tableName,
        item_count: 0,
      },
    },
  ];
}

const rows = values.map((payload) => {
  const spId = payload.Id ?? payload.ID;
  const modifiedAt = payload.Modified;

  if (!spId) {
    throw new Error(`SharePoint item sin Id/ID en lista ${cursor.list_name}.`);
  }

  if (!modifiedAt) {
    throw new Error(`SharePoint item ${spId} sin Modified en lista ${cursor.list_name}.`);
  }

  return {
    spId: Number(spId),
    modifiedAt,
    sql: `(${Number(spId)}, ${jsonSql(payload)}, NOW())`,
  };
});

const maxModifiedAt = rows
  .map((row) => row.modifiedAt)
  .sort()[rows.length - 1];

const upsertSql = `
WITH upserted AS (
    INSERT INTO ${tableName} (
        sp_id,
        payload,
        extracted_at
    )
    VALUES
        ${rows.map((row) => row.sql).join(",\n        ")}
    ON CONFLICT (sp_id)
    DO UPDATE SET
        payload = EXCLUDED.payload,
        extracted_at = NOW()
    RETURNING sp_id
)
SELECT
    ${sqlString(cursor.sync_key)}::text AS sync_key,
    ${sqlString(cursor.list_name)}::text AS list_name,
    ${sqlString(tableName)}::text AS table_name,
    ${sqlString(maxModifiedAt)}::timestamptz AS max_modified_at,
    COUNT(*)::int AS affected_rows
FROM upserted;
`.trim();

return [
  {
    json: {
      has_items: true,
      sync_key: cursor.sync_key,
      list_name: cursor.list_name,
      table_name: tableName,
      item_count: rows.length,
      max_modified_at: maxModifiedAt,
      upsert_sql: upsertSql,
    },
  },
];

/**
 * Convierte la salida del loop de listas en un único item de control.
 *
 * El loop entrega varios items, uno por lista configurada.
 * Las transformaciones SQL no deben ejecutarse una vez por lista, sino una
 * sola vez después de terminar toda la extracción incremental RAW.
 */
const processedLists = $input.all().map((item) => item.json);

return [
  {
    json: {
      phase: "transform",
      processed_list_count: processedLists.length,
      processed_lists: processedLists.map((item) => ({
        sync_key: item.syncKey ?? item.sync_key ?? null,
        list_name: item.listName ?? item.list_name ?? null,
        table_name: item.tableName ?? item.table_name ?? null,
      })),
      started_at: new Date().toISOString(),
    },
  },
];
